use std::collections::BTreeMap;

fn count_colors(colors: Vec<String>) -> Result<BTreeMap<String, usize>, &'static str> {
    if colors.len() > 2500 {
        return Err("Input list has more than 2500 elements");
    }

    let mut color_count: BTreeMap<String, usize> = BTreeMap::new();

    for color in colors {
        let normalized_color = color.to_lowercase();
        *color_count.entry(normalized_color).or_insert(0) += 1;
    }

    Ok(color_count)
}

fn main() {
    let colors = vec!["Red".to_string(), "red".to_string(), "Blue".to_string(), "blue".to_string(), "Green".to_string(), "green".to_string()];
    match count_colors(colors) {
        Ok(color_count) => {
            println!("Color Frequency:");
            for (color, count) in &color_count {
                println!("{}: {}", color, count);
            }
        }
