// Abstract base class for accounts
class Account {
protected:
    std::string accountNumber;
    double balance;
    std::string accountType;

public:
    Account(const std::string& accountNumber, const std::string& accountType, double initialBalance)
        : accountNumber(accountNumber), balance(initialBalance), accountType(accountType) {}

    virtual double calculateInterestRate() = 0;

    virtual void withdraw(double amount) {
        if (amount > balance) {
            throw std::runtime_error("Insufficient funds");
        }
        balance -= amount;
    }

    virtual void deposit(double amount) {
        balance += amount;
    }

    std::string getAccountNumber() const { return accountNumber; }
    std::string getAccountType() const { return accountType; }
    double getBalance() const { return balance; }

    void logAction(const std::string& action) const {
        std::ofstream logFile("account_log.txt", std::ios_base::app);
        if (logFile.is_open()) {
            logFile << accountNumber << " - " << accountType << " - " << action << std::endl;
            logFile.close();
        }
    }
};

// Savings account class
class SavingsAccount : public Account {
public:
    SavingsAccount(const std::string& accountNumber, double initialBalance) : Account(accountNumber, "Savings", initialBalance) {}

    double calculateInterestRate() override {
        return balance * 0.05;
    }
};

// Checking account class
class CheckingAccount : public Account {
public:
    CheckingAccount(const std::string& accountNumber, double initialBalance) : Account(accountNumber, "Checking", initialBalance) {}

    double calculateInterestRate() override {
        return balance * 0.03;
    }
};

// Joint account class
class JointAccount : public Account {
public:
    JointAccount(const std::string& accountNumber, const std::string& accountType, double initialBalance)
        : Account(accountNumber, accountType, initialBalance) {}

    double calculateInterestRate() override {
        return balance * 0.04;
    }
};

// Stack class to hold accounts
class AccountStack {
private:
    std::stack<Account*> accounts;

public:
    void push(const Account& account) {
        accounts.push(&account);
    }

    Account* pop() {
        if (accounts.empty()) {
            throw std::runtime_error("Stack is empty");
        }
        Account* account = accounts.top();
        accounts.pop();
        return account;
    }

    bool isEmpty() const { return accounts.empty(); }
};

int main() {
    // Create accounts
    SavingsAccount savingsAccount("SAV123", 1000);
    CheckingAccount checkingAccount("CHK456", 500);
    JointAccount jointAccount("JOINT789", "Joint", 2000);

    // Create account stack
    AccountStack accountStack;

    // Push accounts onto stack
    accountStack.push(savingsAccount);
    accountStack.push(checkingAccount);
    accountStack.push(jointAccount);

    // Log significant account actions
    savingsAccount.logAction("Opened");
    checkingAccount.logAction("Opened");
    jointAccount.logAction("Opened");

    // Pop accounts from stack and perform operations
    while (!accountStack.isEmpty()) {
        Account* account = accountStack.pop();
        try {
            account->deposit(500);
            account->withdraw(200);
            std::cout << "Account " << account->getAccountNumber() << " balance: " << account->getBalance() << std::endl;
        } catch (const std::exception& e) {
            std::cout << e.what() << std::endl;
        }
    }

    return 0;
}
