package main

import (
    "bufio"
    "fmt"
    "log"
    "net"
    "sync"
    "time"
)

const (
    maxMessages = 200
    maxCapacity = 200
)

var (
    messagesChan = make(chan string, maxCapacity)
    wg          sync.WaitGroup
)

func handleClient(conn net.Conn) {
    defer conn.Close()
    defer wg.Done()

    for {
        select {
        case message, ok := <-messagesChan:
            if !ok {
                return
            }
            fmt.Println("Client:", message)
            _, err := conn.Write([]byte(message + "\n"))
            if err != nil {
                log.Println(err)
                return
            }
        }
    }
}

func main() {
    ln, err := net.Listen("tcp", ":8080")
    if err != nil {
        log.Fatal(err)
    }
    defer ln.Close()

    var mu sync.Mutex
    var count int

    go func() {
        for {
            select {
            case <-time.After(2 * time.Second):
                mu.Lock()
                if count >= maxMessages {
                    mu.Unlock()
                    continue
                }
                mu.Unlock()
                count++
                messagesChan <- fmt.Sprintf("New message from client %d\n", count)
            }
        }
    }()

    for {
        conn, err := ln.Accept()
        if err != nil {
            log.Println(err)
            continue
        }

        wg.Add(1)
        go handleClient(conn)
    }

    wg.Wait()
}
