from collections import defaultdict
import re

class ExpressionEvaluator:
    def __init__(self, max_cache_size=1000):
        self.max_cache_size = max_cache_size
        self.cache = defaultdict(lambda: None)

    def evaluate(self, expression):
        if expression in self.cache:
            return self.cache[expression]

        # Parse the expression and apply the order of operations
        result = self.parse_and_evaluate(expression)

        # Cache the result
        self.cache[expression] = result

        return result

    def parse_and_evaluate(self, expression):
        # Remove whitespace
        expression = re.sub(r'\s', '', expression)

        # Define operator precedence
        precedence = {'+': 1, '-': 1, '*': 2, '/': 2}

        # Tokenize the expression
        tokens = []
        current_token = ''
        for char in expression:
            if char in precedence or char == '(':
                if current_token:
                    tokens.append(current_token)
                    current_token = ''
                tokens.append(char)
            elif char == ')':
                if current_token:
                    tokens.append(current_token)
                    current_token = ''
                tokens.append(char)
            else:
                current_token += char
        if current_token:
            tokens.append(current_token)

        # Apply operator precedence
        output_queue = []
        operator_stack = []
        for token in tokens:
            if token in precedence:
                while (operator_stack and 
                       operator_stack[-1] in precedence and 
                       precedence[operator_stack[-1]] >= precedence[token]):
                    output_queue.append(operator_stack.pop())
                operator_stack.append(token)
            elif token == '(':
                operator_stack.append(token)
            elif token == ')':
                while operator_stack[-1] != '(':
                    output_queue.append(operator_stack.pop())
                operator_stack.pop()
            else:
                output_queue.append(float(token))

        # Evaluate the expression
        while operator_stack:
            output_queue.append(operator_stack.pop())

        # Evaluate the expression
        stack = []
        for token in output_queue:
            if token in precedence:
                operand2 = stack.pop()
                operand1 = stack.pop()
                if token == '+':
                    result = operand1 + operand2
                elif token == '-':
                    result = operand1 - operand2
                elif token == '*':
                    result = operand1 * operand2
                elif token == '/':
                    result = operand1 / operand2
                stack.append(result)
            else:
                stack.append(token)

        return stack[0]

# Example usage
evaluator = ExpressionEvaluator()
print(evaluator.evaluate("1+2*3"))  # Output: 7.0
print(evaluator.evaluate("(1+2)*3"))  # Output: 9.0
