import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.TimeUnit;

public class SessionManager {
    private ConcurrentHashMap<String, Long> sessions;
    private int maxSessions;
    private int maxInactiveInterval;

    public SessionManager(int maxSessions, int maxInactiveInterval) {
        this.maxSessions = maxSessions;
        this.maxInactiveInterval = maxInactiveInterval;
        this.sessions = new ConcurrentHashMap<>();
    }

    public void addSession(String sessionId) {
        if (sessions.size() < maxSessions) {
            sessions.put(sessionId, System.currentTimeMillis());
            System.out.println("Session added: " + sessionId);
        } else {
            System.out.println("Maximum number of sessions reached. Removing oldest session...");
            String oldestSessionId = removeOldestSession();
            if (oldestSessionId != null) {
                sessions.remove(oldestSessionId);
                addSession(sessionId);
            }
        }
    }

    public void removeSession(String sessionId) {
        sessions.remove(sessionId);
        System.out.println("Session removed: " + sessionId);
    }

    public String removeOldestSession() {
        long oldestTimestamp = Long.MAX_VALUE;
        String oldestSessionId = null;
        for (Map.Entry<String, Long> entry : sessions.entrySet()) {
            if (entry.getValue() < oldestTimestamp) {
                oldestTimestamp = entry.getValue();
                oldestSessionId = entry.getKey();
            }
        }
        if (oldestSessionId != null && (System.currentTimeMillis() - oldestTimestamp) > TimeUnit.MINUTES.toMillis(maxInactiveInterval)) {
            System.out.println("Removing inactive session: " + oldestSessionId);
            return oldestSessionId;
        }
        return null;
    }

    public static void main(String[] args) {
        SessionManager sessionManager = new SessionManager(500, 30);
        sessionManager.addSession("session1");
        sessionManager.addSession("session2");
        sessionManager.addSession("session3");
        sessionManager.removeSession("session2");
        sessionManager.addSession("session4");
    }
}
