import java.util.PriorityQueue;

class Node {
    int data;
    Node next;

    public Node(int data) {
        this.data = data;
        this.next = null;
    }
}

class LinkedList {
    Node head;

    public LinkedList() {
        this.head = null;
    }

    public void append(int data) {
        Node newNode = new Node(data);
        if (head == null) {
            head = newNode;
            return;
        }
        Node last = head;
        while (last.next != null) {
            last = last.next;
        }
        last.next = newNode;
    }

    public int size() {
        int count = 0;
        Node temp = head;
        while (temp != null) {
            count++;
            temp = temp.next;
        }
        return count;
    }

    public void printList() {
        Node temp = head;
        while (temp != null) {
            System.out.print(temp.data + " ");
            temp = temp.next;
        }
        System.out.println();
    }
}

public class Main {
    public static LinkedList mergeSortedLinkedLists(LinkedList[] lists) {
        if (lists == null || lists.length == 0) {
            return null;
        }

        PriorityQueue<Node> minHeap = new PriorityQueue<>((a, b) -> a.data - b.data);
        for (LinkedList list : lists) {
            if (list != null && list.head != null) {
                minHeap.add(list.head);
            }
        }

        LinkedList mergedList = new LinkedList();
        while (!minHeap.isEmpty()) {
            if (mergedList.size() >= 10000) {
                break;
            }
            Node minNode = minHeap.poll();
            mergedList.append(minNode.data);
            if (minNode.next != null) {
                minHeap.add(minNode.next);
            }
        }
        return mergedList;
    }

    public static void main(String[] args) {
        LinkedList list1 = new LinkedList();
        list1.append(1);
        list1.append(3);
        list1.append(5);

        LinkedList list2 = new LinkedList();
        list2.append(2);
        list2.append(4);
        list2.append(6);

        LinkedList list3 = new LinkedList();
        list3.append(0);
        list3.append(7);
        list3.append(8);

        LinkedList[] lists = {list1, list2, list3};
        LinkedList mergedList = mergeSortedLinkedLists(lists);
        mergedList.printList();
    }
}
