import (
	"errors"
	"fmt"
)

type Student struct {
	Name string
	Grade float64
}

var gradeRecords = make([]Student, 0, 2000)

func addGrade(name string, grade float64) error {
	for _, record := range gradeRecords {
		if record.Name == name {
			return errors.New("student already exists")
		}
	}

	gradeRecords = append(gradeRecords, Student{Name: name, Grade: grade})
	return nil
}

func updateGrade(name string, grade float64) error {
	for _, record := range gradeRecords {
		if record.Name == name {
			record.Grade = grade
			return nil
		}
	}

	return errors.New("student not found")
}

func listGrades() {
	for _, record := range gradeRecords {
		fmt.Printf("%s: %f\n", record.Name, record.Grade)
	}
}

func main() {
	for {
		fmt.Println("\n1. Add Grade")
		fmt.Println("2. Update Grade")
		fmt.Println("3. List Grades")
		fmt.Println("4. Exit")

		var choice int
		fmt.Scanln(&choice)

		switch choice {
		case 1:
			var name string
			var grade float64
			fmt.Scanln(&name, &grade)
			if err := addGrade(name, grade); err != nil {
				fmt.Println(err)
			}
		case 2:
			var name string
			var grade float64
			fmt.Scanln(&name, &grade)
			if err := updateGrade(name, grade); err != nil {
				fmt.Println(err)
			}
		case 3:
			listGrades()
		case 4:
			return
		default:
			fmt.Println("Invalid choice")
		}
	}
}
