#include <vector>
#include <string>

class FlightReservationSystem {
public:
    FlightReservationSystem(int maxFlightsPerAirline) 
        : maxFlightsPerAirline(maxFlightsPerAirline) {}

    void addAirline(const std::string& airlineName) {
        if (airlineMap.find(airlineName) != airlineMap.end()) {
            std::cout << "Airline already exists." << std::endl;
            return;
        }
        if (airlineMap.size() >= 10) {
            std::cout << "Maximum number of airlines reached." << std::endl;
            return;
        }
        airlineMap[airlineName] = {};
        std::cout << "Airline added successfully." << std::endl;
    }

    void addFlight(const std::string& airlineName, const std::string& flightNumber, int numSeats) {
        if (airlineMap.find(airlineName) == airlineMap.end()) {
            std::cout << "Airline does not exist." << std::endl;
            return;
        }
        if (airlineMap[airlineName].size() >= maxFlightsPerAirline) {
            std::cout << "Maximum number of flights reached for this airline." << std::endl;
            return;
        }
        airlineMap[airlineName].push_back({flightNumber, numSeats});
        std::cout << "Flight added successfully." << std::endl;
    }

    void bookSeat(const std::string& airlineName, const std::string& flightNumber, int seatNumber) {
        if (airlineMap.find(airlineName) == airlineMap.end()) {
            std::cout << "Airline does not exist." << std::endl;
            return;
        }
        for (const auto& flight : airlineMap[airlineName]) {
            if (flight.first == flightNumber) {
                if (seatNumber < 1 || seatNumber > flight.second) {
                    std::cout << "Invalid seat number." << std::endl;
                    return;
                }
                if (flight.second - seatNumber <= 0) {
                    std::cout << "Seat is already booked or not available." << std::endl;
                    return;
                }
                flight.second -= seatNumber;
                std::cout << "Seat booked successfully." << std::endl;
                return;
            }
        }
        std::cout << "Flight does not exist." << std::endl;
    }

    void cancelFlight(const std::string& airlineName, const std::string& flightNumber) {
        if (airlineMap.find(airlineName) == airlineMap.end()) {
            std::cout << "Airline does not exist." << std::endl;
            return;
        }
        for (auto it = airlineMap[airlineName].begin(); it != airlineMap[airlineName].end();) {
            if (it->first == flightNumber) {
                int availableSeats = it->second;
                std::cout << "Flight cancelled successfully. " << availableSeats << " seats available." << std::endl;
                it = airlineMap[airlineName].erase(it);
            } else {
                ++it;
            }
        }
        std::cout << "Flight does not exist." << std::endl;
    }

    void printAvailability(const std::string& airlineName) {
        if (airlineMap.find(airlineName) == airlineMap.end()) {
            std::cout << "Airline does not exist." << std::endl;
            return;
        }
        std::cout << "Available seats for " << airlineName << ":" << std::endl;
        for (const auto& flight : airlineMap[airlineName]) {
            std::cout << flight.first << ": " << flight.second << std::endl;
        }
    }

private:
    std::map<std::string, std::vector<Flight>> airlineMap;
    int maxFlightsPerAirline;
};

struct Flight {
    std::string flightNumber;
    int numSeats;
};

int main() {
    FlightReservationSystem system(300);
    system.addAirline("Air India");
    system.addFlight("Air India", "AI101", 200);
    system.bookSeat("Air India", "AI101", 10);
    system.printAvailability("Air India");
    system.cancelFlight("Air India", "AI101");
    system.printAvailability("Air India");
    return 0;
}
