use std::collections::VecDeque;

struct Task {
    description: String,
    completed: bool,
}

impl Task {
    fn new(description: String) -> Task {
        Task {
            description,
            completed: false,
        }
    }
}

struct TaskManager {
    tasks: VecDeque<Task>,
}

impl TaskManager {
    fn new() -> TaskManager {
        TaskManager {
            tasks: VecDeque::with_capacity(50),
        }
    }

    fn add_task(&mut self, description: String) {
        if self.tasks.len() >= 50 {
            println!("Task list is full. Please remove a task first.");
            return;
        }
        let task = Task::new(description);
        self.tasks.push_back(task);
    }

    fn remove_task(&mut self) -> Option<String> {
        if self.tasks.is_empty() {
            None
        } else {
            let task = self.tasks.pop_front().unwrap();
            let description = task.description.clone();
            println!("Task removed: {}", description);
            Some(description)
        }
    }

    fn view_tasks(&self) {
        for (index, task) in self.tasks.iter().enumerate() {
            let completed = if task.completed { "X" } else { "-" };
            println!("{} - {} - {}", index, completed, task.description);
        }
    }
}

fn main() {
    let mut task_manager = TaskManager::new();

    loop {
        println!("Task Manager CLI");
        println!("1. Add task");
        println!("2. Remove task");
        println!("3. View tasks");
        println!("4. Quit");

        let mut input = String::new();
        std::io::stdin().read_line(&mut input).unwrap();
        let input: u32 = match input.trim().parse() {
            Ok(num) => num,
            Err(_) => continue,
        };

        match input {
            1 => {
                println!("Enter task description:");
                let mut description = String::new();
                std::io::stdin().read_line(&mut description).unwrap();
                task_manager.add_task(description.trim().to_string());
            }
            2 => task_manager.remove_task(),
            3 => task_manager.view_tasks(),
            4 => break,
            _ => println!("Invalid choice. Please try again."),
        }
    }
}
