import java.util.List;

class FileMetadata {
    String filename;
    long lastModified;
    long fileSize;

    public FileMetadata(String filename, long lastModified, long fileSize) {
        this.filename = filename;
        this.lastModified = lastModified;
        this.fileSize = fileSize;
    }
}

public class FileMetadataCache {
    private List<FileMetadata> cache;
    private long cacheSize;

    public FileMetadataCache() {
        this.cache = new ArrayList<>();
        this.cacheSize = 1000;
    }

    public void addFile(String filename, long lastModified, long fileSize) {
        if (cache.size() >= cacheSize) {
            removeOldestFile();
        }
        cache.add(new FileMetadata(filename, lastModified, fileSize));
    }

    public FileMetadata getFileMetadata(String filename) {
        for (FileMetadata file : cache) {
            if (file.filename.equals(filename)) {
                return file;
            }
        }
        return null;
    }

    public void removeFile(String filename) {
        cache.removeIf(file -> file.filename.equals(filename));
    }

    private void removeOldestFile() {
        cache.remove(0);
    }

    public static void main(String[] args) {
        FileMetadataCache cache = new FileMetadataCache();
        cache.addFile("file1.txt", System.currentTimeMillis(), 1024);
        cache.addFile("file2.txt", System.currentTimeMillis(), 2048);
        System.out.println(cache.getFileMetadata("file1.txt").fileSize);
        cache.removeFile("file2.txt");
    }
}
