const (
    maxTemperatureEntries = 1000
    maxBufferCapacity     = 1000
)

type Temperature struct {
    SensorID  string
    Temperature float64
}

type TemperatureProcessor struct {
    temperatureBuffer *bufio.Reader
    temperatureWriter  *bufio.Writer
    movingAverage     float64
    bufferCapacity    int
    bufferCount       int
    mu                sync.Mutex
    log                log.Logger
}

func NewTemperatureProcessor() *TemperatureProcessor {
    temperatureBuffer := bufio.NewReader(bufio.NewBuffer(make([]byte, maxBufferCapacity)))
    temperatureWriter := bufio.NewWriter(bufio.NewBuffer(make([]byte, maxBufferCapacity)))

    return &TemperatureProcessor{
        temperatureBuffer,
        temperatureWriter,
        0.0,
        maxBufferCapacity,
        0,
        log.New(log.Writer(), "[TemperatureProcessor]", log.LstdFlags|log.Lshortfile),
    }
}

func (t *TemperatureProcessor) ProcessTemperature(temp Temperature) error {
    if t.bufferCount >= t.bufferCapacity {
        return fmt.Errorf("overflow: buffer is full")
    }

    t.mu.Lock()
    defer t.mu.Unlock()

    t.temperatureBuffer.Write([]byte(fmt.Sprintf("%s %f\n", temp.SensorID, temp.Temperature)))
    t.bufferCount++

    if t.bufferCount == t.bufferCapacity {
        t.movingAverage = t.calculateMovingAverage()
    }

    return nil
}

func (t *TemperatureProcessor) calculateMovingAverage() float64 {
    sum := 0.0
    for i := 0; i < t.bufferCount; i++ {
        temp := Temperature{}
        err := t.temperatureBuffer.Read([]byte(fmt.Sprintf("%s %f\n", "sensor", 0)))
        if err != nil {
            return 0.0
        }
        fmt.Sscanf(string(err), "%s %f", &temp.SensorID, &temp.Temperature)
        sum += temp.Temperature
    }

    return sum / float64(t.bufferCount)
}

func (t *TemperatureProcessor) GetMovingAverage() float64 {
    t.mu.Lock()
    defer t.mu.Unlock()

    return t.movingAverage
}

func main() {
    processor := NewTemperatureProcessor()

    ctx := context.Background()
    for i := 0; i < 1000; i++ {
        processor.ProcessTemperature(Temperature{string(i), float64(i)})
    }

    fmt.Println(processor.GetMovingAverage())
}
