private:
    std::map<std::string, std::map<std::string, Product>> catalog;

    // Custom sorting function
    void sortProducts(std::vector<Product>& products, std::string sortType) {
        if (sortType == "price") {
            std::sort(products.begin(), products.end(), sortByPrice);
        } else if (sortType == "genre") {
            std::sort(products.begin(), products.end(), sortByGenre);
        }
    }

