    // Add product to catalog
    void addProduct(std::string genre, double price, int quantity) {
        catalog[genre][std::to_string(price)] = Product(genre, price, quantity);
    }

    // Remove product from catalog
    void removeProduct(std::string genre, double price) {
        catalog[genre].erase(std::to_string(price));
    }

    // Update product quantity
    void updateQuantity(std::string genre, double price, int quantity) {
        if (catalog[genre].find(std::to_string(price)) != catalog[genre].end()) {
            catalog[genre][std::to_string(price)].quantity = quantity;
        }
    }

    // Calculate total cost
    double calculateTotalCost(std::string genre, double price) {
        if (catalog[genre].find(std::to_string(price)) != catalog[genre].end()) {
