// Custom comparison function for age
struct AgeComparator {
    bool operator()(const std::string& a, const std::string& b) const {
        return a > b;
    }
};

// Custom comparison function for name
struct NameComparator {
    bool operator()(const std::string& a, const std::string& b) const {
        if (a.size() == b.size()) {
            return a < b;
        }
        return a.size() > b.size();
    }
};

class Employee {
public:
    Employee(const std::string& name, int age) : name_(name), age_(age) {}

    std::string getName() const { return name_; }
    int getAge() const { return age_; }

private:
    std::string name_;
    int age_;
};

class EmployeeManager {
public:
    void addEmployee(const Employee& employee) {
        if (employees_.empty()) {
            employees_.push_back(employee);
        } else if (employees_.capacity() == 800) {
            throw std::runtime_error("Deque capacity exceeded.");
        } else {
            employees_.push_back(employee);
        }
    }

    std::deque<Employee> getEmployees() const {
        return employees_;
    }

private:
    std::deque<Employee> employees_;
};

void stableSort(std::deque<Employee>& employees, AgeComparator& ageComparator, NameComparator& nameComparator) {
    for (auto it = employees.begin(); it != employees.end(); ++it) {
        auto nameIt = std::find_if(employees.begin(), it, nameComparator);
        if (nameIt != it) {
            std::swap(*it, *nameIt);
            nameIt = std::find_if(employees.begin(), it, nameComparator);
            if (nameIt != it) {
                std::swap(*it, *nameIt);
            }
        }
    }
}

int main() {
    try {
        EmployeeManager manager;
        manager.addEmployee(Employee("John", 30));
        manager.addEmployee(Employee("Alice", 25));
        manager.addEmployee(Employee("Bob", 40));
        manager.addEmployee(Employee("Charlie", 20));

        AgeComparator ageComparator;
        NameComparator nameComparator;

        stableSort(manager.getEmployees(), ageComparator, nameComparator);

        for (const auto& employee : manager.getEmployees()) {
            std::cout << "Name: " << employee.getName() << ", Age: " << employee.getAge() << std::endl;
        }
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
