use std::collections::LinkedList;
use std::error::Error;
use std::time::SystemTime;

enum Operation {
    Enqueue(String, String),
    Dequeue,
    Lookup(String),
}

struct Message {
    id: String,
    timestamp: String,
}

struct MessageQueue {
    queue: LinkedList<Message>,
    max_size: usize,
}

impl MessageQueue {
    fn new(max_size: usize) -> Self {
        MessageQueue {
            queue: LinkedList::new(),
            max_size,
        }
    }

    fn execute(&mut self, op: Operation) -> Result<(), Box<dyn Error>> {
        match op {
            Operation::Enqueue(id, timestamp) => {
                if self.queue.len() >= self.max_size {
                    return Err(Box::new(MessageQueueOverflowError));
                }
                let message = Message {
                    id: id.to_string(),
                    timestamp: timestamp.to_string(),
                };
                self.queue.push_back(message);
                Ok(())
            }
            Operation::Dequeue => {
                if self.queue.is_empty() {
                    return Err(Box::new(MessageQueueUnderflowError));
                }
                self.queue.pop_front();
                Ok(())
            }
            Operation::Lookup(id) => {
                for message in &self.queue {
                    if message.id == id {
                        return Ok(());
                    }
                }
                Err(Box::new(MessageNotFoundError))
            }
        }
    }
}

struct MessageQueueOverflowError;

impl Error for MessageQueueOverflowError {}

impl std::fmt::Display for MessageQueueOverflowError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "Message queue overflow")
    }
}

struct MessageQueueUnderflowError;

impl Error for MessageQueueUnderflowError {}

impl std::fmt::Display for MessageQueueUnderflowError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "Message queue underflow")
    }
}

struct MessageNotFoundError;

impl Error for MessageNotFoundError {}

impl std::fmt::Display for MessageNotFoundError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "Message not found")
    }
}

fn main() {
    let mut queue = MessageQueue::new(500);
    let current_time = SystemTime::now().duration_since(SystemTime::UNIX_EPOCH).unwrap().as_secs();
    queue.execute(Operation::Enqueue("1".to_string(), current_time.to_string())).unwrap();
    queue.execute(Operation::Enqueue("2".to_string(), current_time + 1)).unwrap();
    queue.execute(Operation::Enqueue("3".to_string(), current_time + 2)).unwrap();
    queue.execute(Operation::Enqueue("4".to_string(), current_time + 3)).unwrap();
    queue.execute(Operation::Enqueue("5".to_string(), current_time + 4)).unwrap();
    queue.execute(Operation::Enqueue("6".to_string(), current_time + 5)).unwrap();
