#include <iostream>
#include <set>
#include <thread>
#include <mutex>
#include <chrono>
#include <stdexcept>

using namespace std;

class Cinema {
private:
    set<pair<int, int>, greater<pair<int, int>>> bookings;
    const int MAX_BOOKINGS = 10000;

public:
    Cinema() {
        if (bookings.size() >= MAX_BOOKINGS) {
            throw runtime_error("Maximum bookings reached. Cannot add more bookings.");
        }
    }

    void reserveSeat(int row, int seat) {
        if (row < 1 || row > 10 || seat < 1 || seat > 10) {
            throw invalid_argument("Invalid row or seat number. Please enter a number between 1 and 10.");
        }

        if (bookings.find({row, seat}) != bookings.end()) {
            throw runtime_error("Seat already booked.");
        }

        bookings.insert({row, seat});
        cout << "Seat " << row << "," << seat << " reserved successfully." << endl;
    }

    void cancelReservation(int row, int seat) {
        if (row < 1 || row > 10 || seat < 1 || seat > 10) {
            throw invalid_argument("Invalid row or seat number. Please enter a number between 1 and 10.");
        }

        if (bookings.find({row, seat}) == bookings.end()) {
            throw runtime_error("Seat not booked.");
        }

        bookings.erase({row, seat});
        cout << "Seat " << row << "," << seat << " cancelled successfully." << endl;
    }

    bool isSeatAvailable(int row, int seat) {
        if (row < 1 || row > 10 || seat < 1 || seat > 10) {
            throw invalid_argument("Invalid row or seat number. Please enter a number between 1 and 10.");
        }

        return bookings.find({row, seat}) == bookings.end();
    }

    void checkAvailability() {
        cout << "Available seats: ";
        for (const auto& booking : bookings) {
            cout << booking.first << "," << booking.second << " ";
        }
        cout << endl;
    }
};

class ThreadFunction {
public:
    void operator()(Cinema& cinema, int row, int seat) {
        try {
            cinema.reserveSeat(row, seat);
            this_thread::sleep_for(chrono::seconds(1));
            cinema.cancelReservation(row, seat);
        } catch (const exception& e) {
            cout << e.what() << endl;
        }
    }
};

int main() {
    Cinema cinema;

    // Simulating multiple threads for concurrent booking
    thread threads[10];
    for (int i = 0; i < 10; i++) {
        int row = rand() % 10 + 1;
        int seat = rand() % 10 + 1;
        threads[i] = thread(ThreadFunction(), ref(cinema), row, seat);
    }

    for (thread& t : threads) {
        t.join();
    }

    cinema.checkAvailability();

    return 0;
}
