import heapq
import datetime

class TaskManager:
    def __init__(self, max_tasks=50):
        self.max_tasks = max_tasks
        self.tasks = []
        self.deadline_map = {}

    def add_task(self, task_name, deadline):
        if len(self.tasks) >= self.max_tasks:
            self.delete_oldest_task()
        task = (deadline, task_name)
        heapq.heappush(self.tasks, task)
        self.deadline_map[task_name] = deadline

    def update_task(self, task_name, new_deadline):
        if task_name not in self.deadline_map:
            print(f"Task '{task_name}' not found.")
            return
        deadline = self.deadline_map[task_name]
        heapq.heappushpop(self.tasks, (new_deadline, task_name))
        self.deadline_map[task_name] = new_deadline

    def delete_task(self, task_name):
        if task_name not in self.deadline_map:
            print(f"Task '{task_name}' not found.")
            return
        task = self.deadline_map.pop(task_name)
        heapq.heappop(self.tasks)

    def get_next_task(self):
        if not self.tasks:
            return None
        return heapq.heappop(self.tasks)[1]

    def print_tasks(self):
        print("Tasks:")
        for task in self.tasks:
            deadline = datetime.datetime.strptime(self.deadline_map[task[1]], "%Y-%m-%d %H:%M:%S")
            print(f"Task: {task[1]}, Deadline: {deadline}")


def main():
    manager = TaskManager()
    while True:
        print("\n1. Add task")
        print("2. Update task")
        print("3. Delete task")
