import java.util.TreeSet;
import java.util.logging.Level;
import java.util.logging.Logger;

public class TaskScheduler {

    private static final int MAX_TASKS = 200;
    private static final Logger logger = Logger.getLogger(TaskScheduler.class.getName());

    private TreeSet<Task> taskSet;

    public TaskScheduler() {
        taskSet = new TreeSet<>();
    }

    public void addTask(Task task) {
        if (taskSet.size() >= MAX_TASKS) {
            logger.severe("Task scheduler is full. Cannot add task with ID " + task.getId());
            throw new RuntimeException("Task scheduler is full");
        }
        logger.info("Adding task with ID " + task.getId() + " and priority " + task.getPriority());
        taskSet.add(task);
    }

    public void removeTask(Task task) {
        if (!taskSet.contains(task)) {
            logger.severe("Task with ID " + task.getId() + " does not exist in the task scheduler");
            throw new RuntimeException("Task does not exist in task scheduler");
        }
        logger.info("Removing task with ID " + task.getId());
        taskSet.remove(task);
    }

    public Task fetchTask(int taskId) {
        for (Task task : taskSet) {
            if (task.getId() == taskId) {
                logger.info("Fetching task with ID " + taskId);
                return task;
            }
        }
        logger.severe("Task with ID " + taskId + " does not exist in the task scheduler");
        throw new RuntimeException("Task does not exist in task scheduler");
    }

    public static class Task {
        private int id;
        private int priority;

        public Task(int id, int priority) {
            this.id = id;
            this.priority = priority;
        }

        public int getId() {
            return id;
        }

        public int getPriority() {
            return priority;
        }

        @Override
        public boolean equals(Object o) {
            if (this == o) return true;
            if (o == null || getClass() != o.getClass()) return false;
            Task task = (Task) o;
            return id == task.id && priority == task.priority;
        }

        @Override
        public int hashCode() {
            return java.util.Objects.hash(id, priority);
        }
    }

    public static void main(String[] args) {
        TaskScheduler scheduler = new TaskScheduler();

        Task task1 = new TaskScheduler.Task(1, 1);
        Task task2 = new TaskScheduler.Task(2, 2);
        Task task3 = new TaskScheduler.Task(3, 3);

        scheduler.addTask(task1);
        scheduler.addTask(task2);
        scheduler.addTask(task3);

        Task fetchedTask = scheduler.fetchTask(2);
        System.out.println("Fetched Task ID: " + fetchedTask.getId() + ", Priority: " + fetchedTask.getPriority());

        scheduler.removeTask(task2);
        try {
            scheduler.fetchTask(2);
        } catch (RuntimeException e) {
            System.out.println(e.getMessage());
        }
    }
}
