using namespace std;

class Inventory {
private:
    priority_queue<pair<int, string>> queue;
    int max_size;

public:
    Inventory() : max_size(500) {}

    void add_item(string item, int priority) {
        if (queue.size() >= max_size) {
            throw runtime_error("Inventory is full. Cannot add more items.");
        }
        queue.push(make_pair(priority, item));
    }

    void remove_item() {
        if (queue.empty()) {
            throw runtime_error("Inventory is empty. Cannot remove items.");
        }
        queue.pop();
    }

    string retrieve_item() {
        if (queue.empty()) {
            throw runtime_error("Inventory is empty. Cannot retrieve items.");
        }
        string item = queue.top().second;
        queue.pop();
        return item;
    }
};

int main() {
