enum MediaType {
    Book(String, u32),
    Movie(String, u32),
    Music(String, u32),
}

struct Library {
    media: VecDeque<MediaType>,
}

impl Library {
    fn new() -> Self {
        Library {
            media: VecDeque::with_capacity(1000),
        }
    }

    fn add_media(&mut self, media_type: MediaType) -> Result<(), &'static str> {
        if self.media.len() >= 1000 {
            return Err("Library is full");
        }
        self.media.push_back(media_type);
        Ok(())
    }

    fn get_media(&self, index: usize) -> Result<MediaType, &'static str> {
        if index >= self.media.len() {
            return Err("Index out of bounds");
        }
        Ok(self.media.get(index).cloned().unwrap())
    }

    fn update_media(&mut self, index: usize, media_type: MediaType) -> Result<(), &'static str> {
        if index >= self.media.len() {
            return Err("Index out of bounds");
        }
        self.media.remove(index);
        self.media.push_back(media_type);
        Ok(())
    }

    fn delete_media(&mut self, index: usize) -> Result<(), &'static str> {
        if index >= self.media.len() {
            return Err("Index out of bounds");
        }
        self.media.remove(index);
        Ok(())
    }
}

fn main() {
    let mut library = Library::new();

    match library.add_media(MediaType::Book("To Kill a Mockingbird".to_string(), 1)) {
        Ok(_) => println!("Added book"),
        Err(e) => println!("Error: {}", e),
    }

    match library.add_media(MediaType::Movie("The Shawshank Redemption".to_string(), 2)) {
        Ok(_) => println!("Added movie"),
        Err(e) => println!("Error: {}", e),
