    match library.get_media(0) {
        Ok(media) => println!("Book: {:?}", media),
        Err(e) => println!("Error: {}", e),
    }

    match library.update_media(1, MediaType::Movie("The Dark Knight".to_string(), 2)) {
        Ok(_) => println!("Updated media"),
        Err(e) => println!("Error: {}", e),
    }

    match library.delete_media(0) {
        Ok(_) => println!("Deleted media"),
        Err(e) => println!("Error: {}", e),
    }

    println!("{:?}", library.media);
