import queue
import sys

def floyd_warshall(graph):
    num_nodes = len(graph)
    distance_matrix = [[sys.maxsize for _ in range(num_nodes)] for _ in range(num_nodes)]

    # Initialize distance matrix with graph weights
    for i in range(num_nodes):
        for j in range(num_nodes):
            if i == j:
                distance_matrix[i][j] = 0
            elif graph[i][j] != 0:
                distance_matrix[i][j] = graph[i][j]

    # Create a queue to store node pairs to be computed
    node_pairs_queue = queue.Queue()
    for i in range(num_nodes):
        for j in range(i + 1, num_nodes):
            node_pairs_queue.put((i, j))

    while not node_pairs_queue.empty():
        node_pair = node_pairs_queue.get()
        i, j = node_pair

        # Compute distance using Floyd-Warshall algorithm
        for k in range(num_nodes):
            if distance_matrix[i][k] + distance_matrix[k][j] < distance_matrix[i][j]:
                distance_matrix[i][j] = distance_matrix[i][k] + distance_matrix[k][j]

                # Add next node pairs to the queue
                for next_i in range(num_nodes):
                    if next_i != i and next_i != j:
                        node_pairs_queue.put((next_i, j))

    return distance_matrix

# Example usage:
graph = [[0, 5, 0, 10],
         [0, 0, 3, 0],
         [0, 0, 0, 1],
         [0, 0, 0, 0]]

distance_matrix = floyd_warshall(graph)
for row in distance_matrix:
    print(row)
