const MAX_TUPLES: usize = 100;

struct EmployeeScore {
    employee_id: String,
    score: f64,
}

fn calculate_average_score(scores: &ArrayVec<EmployeeScore>) -> Result<f64, Box<dyn Error>> {
    let mut unique_scores: HashMap<String, f64> = HashMap::new();

    for score in scores {
        if let Some(value) = unique_scores.get_mut(&score.employee_id) {
            *value += score.score;
        } else {
            unique_scores.insert(score.employee_id.clone(), score.score);
        }
    }

    let average_score: f64 = unique_scores.values().map(|x| *x).sum::<f64>() / unique_scores.len() as f64;

    Ok(average_score)
}

fn main() -> Result<(), Box<dyn Error>> {
    env_logger::init();

    let mut scores = ArrayVec::<EmployeeScore>::with_capacity(MAX_TUPLES);

    let mut file = File::open("scores.txt")?;
    let mut reader = io::BufReader::new(file);

    let mut buffer = String::new();
    loop {
        let mut line = String::new();
        if let Ok(n) = reader.read_line(&mut line) {
            if n == 0 {
                break;
            }
            let line = line.trim();
            let parts: Vec<_> = line.split(',').map(str::to_string).collect();
            if parts.len() != 2 {
                error!("Invalid data entry: {}", line);
                continue;
            }
            let employee_id = parts[0].clone();
            let score = parts[1].parse::<f64>().map_err(|_| io::Error::new(io::ErrorKind::InvalidInput, "Invalid score"))?;
            scores.push(EmployeeScore { employee_id, score });
        } else {
            error!("Error reading from file: {}", line);
            break;
        }
    }

    let average_score = calculate_average_score(&scores)?;

    let mut writer = BufWriter::new(io::stdout());
    writeln!(writer, "Average score: {}", average_score)?;

    Ok(())
}
