struct Node {
    int data;
    Node* next;
};

bool hasLoop(Node* head) {
    std::unordered_set<Node*> visited;

    while (head) {
        if (visited.find(head) != visited.end()) {
            return true;
        }

        visited.insert(head);
        head = head->next;
    }

    return false;
}

