    Node* node1 = new Node{1};
    Node* node2 = new Node{2};
    Node* node3 = new Node{3};
    Node* node4 = new Node{4};

    node1->next = node2;
    node2->next = node3;
    node3->next = node4;
    node4->next = node2; // Create a loop

    std::cout << std::boolalpha << hasLoop(node1) << std::endl; // Output: true

    // Clean up memory
    delete node1;
    delete node2;
    delete node3;
    delete node4;

    return 0;
