public class StockAnalyzer {

    public static void main(String[] args) {
        ArrayList<Double> prices = new ArrayList<>();
        for (int i = 0; i < 2000; i++) {
            prices.add((double) (Math.random() * 100));
        }

        System.out.println("Stock Prices: " + prices);
        System.out.println("Greatest Profit: " + greatestProfit(prices));
    }

    public static double greatestProfit(ArrayList<Double> prices) {
        if (prices.size() < 2) {
            return 0;
        }

        int minPriceIndex = 0;
        double minPrice = prices.get(0);
        double maxProfit = 0;

        for (int i = 1; i < prices.size(); i++) {
            if (prices.get(i) < minPrice) {
                minPrice = prices.get(i);
                minPriceIndex = i;
            } else if (prices.get(i) - minPrice > maxProfit) {
                maxProfit = prices.get(i) - minPrice;
            }
        }

        return maxProfit;
    }
}
