func processStockPrices(prices chan float64, wg *sync.WaitGroup) {
    defer wg.Done()
    var sum float64
    for price := range prices {
        sum += price
        if sum >= 1000 {
            avg := rollingAverage(prices[:1000])
            fmt.Println(avg)
            sum = 0
        }
    }
}

func main() {
