    prices := make(chan float64, 1000)
    for i := 0; i < 10000; i++ {
        prices <- float64(i)
    }
    prices = close(prices)

    for i := 0; i < 10; i++ {
        wg.Add(1)
        go processStockPrices(prices, &wg)
    }

    wg.Wait()
