package main

import (
	"fmt"
	"sync"
)

type Book struct {
	Title    string
	Author   string
	Year     int
	Issued   bool
}

type Library struct {
	books  map[string]Book
	mu     sync.RWMutex
}

func NewLibrary() *Library {
	return &Library{
		books: make(map[string]Book),
	}
}

func (l *Library) AddBook(title, author, year string) {
	l.mu.Lock()
	defer l.mu.Unlock()
	l.books[title] = Book{
		Title:    title,
		Author:   author,
		Year:     year,
		Issued:   false,
	}
}

func (l *Library) RemoveBook(title string) bool {
	l.mu.RLock()
	defer l.mu.RUnlock()
	if _, ok := l.books[title]; ok {
		delete(l.books, title)
		return true
	}
	return false
}

func (l *Library) UpdateBookStatus(title string, status bool) bool {
	l.mu.RLock()
	defer l.mu.RUnlock()
	if _, ok := l.books[title]; ok {
		l.books[title].Issued = status
		return true
	}
	return false
}

func (l *Library) SearchBook(title string) (bool, Book) {
	l.mu.RLock()
	defer l.mu.RUnlock()
	if book, ok := l.books[title]; ok {
		return true, book
	}
	return false, Book{}
}

func (l *Library) PrintBooks() {
	l.mu.RLock()
	defer l.mu.RUnlock()
	for _, book := range l.books {
		fmt.Printf("Title: %s, Author: %s, Year: %d, Issued: %v\n", book.Title, book.Author, book.Year, book.Issued)
	}
}

func main() {
	library := NewLibrary()

	library.AddBook("Book1", "Author1", 2020)
	library.AddBook("Book2", "Author2", 2021)

	library.PrintBooks()

	library.UpdateBookStatus("Book1", true)

	library.PrintBooks()

	library.RemoveBook("Book2")

	library.PrintBooks()
}
