from datetime import datetime, timedelta

class EnvironmentalSensor:
    def __init__(self):
        self.daily_aggregates = {}
        self.current_date = datetime.now()

    def append_data(self, temperature, humidity):
        if self.current_date.day in self.daily_aggregates:
            self.daily_aggregates[self.current_date.day]['min'].append(temperature)
            self.daily_aggregates[self.current_date.day]['max'].append(temperature)
            self.daily_aggregates[self.current_date.day]['mean'].append(temperature)
        else:
            self.daily_aggregates[self.current_date.day] = {
                'min': [temperature],
                'max': [temperature],
                'mean': [temperature]
            }
        self.current_date += timedelta(days=1)

    def get_aggregates(self, day):
        if day in self.daily_aggregates:
            return self.daily_aggregates[day]
        else:
            return None

    def get_mean(self, day):
        aggregates = self.get_aggregates(day)
        if aggregates:
            return sum(aggregates['mean']) / len(aggregates['mean'])
        else:
            return None

    def get_max(self, day):
        aggregates = self.get_aggregates(day)
        if aggregates:
            return max(aggregates['max'])
        else:
            return None

    def get_min(self, day):
        aggregates = self.get_aggregates(day)
        if aggregates:
            return min(aggregates['min'])
        else:
            return None


def main():
