#include <iostream>
#include <vector>
#include <algorithm>
#include <string>

using namespace std;

void getPermutations(vector<int>& nums, int start, int end, vector<vector<int>>& perms, vector<vector<int>>& uniquePerms) {
    if (start == end) {
        sort(nums.begin(), nums.end());
        uniquePerms.push_back(nums);
        return;
    }
    for (int i = start; i <= end; i++) {
        swap(nums[start], nums[i]);
        getPermutations(nums, start + 1, end, perms, uniquePerms);
        swap(nums[start], nums[i]);
    }
}

void permuteUnique(vector<int>& nums, vector<vector<int>>& perms, vector<vector<int>>& uniquePerms) {
    vector<int> temp;
    getPermutations(nums, 0, nums.size() - 1, perms, uniquePerms);
    uniquePerms.erase(unique(uniquePerms.begin(), uniquePerms.end(), [](const vector<int>& a, const vector<int>& b) {
        return a == b;
    }), uniquePerms.end());
}

void printPermutations(const vector<vector<int>>& uniquePerms) {
    cout << "[";
    for (int i = 0; i < uniquePerms.size(); i++) {
        cout << "[";
        for (int j = 0; j < uniquePerms[i].size(); j++) {
            cout << uniquePerms[i][j];
            if (j != uniquePerms[i].size() - 1) {
                cout << ", ";
            }
        }
        cout << "]";
        if (i != uniquePerms.size() - 1) {
            cout << ", ";
        }
    }
    cout << "]" << endl;
}

int main() {
    vector<int> nums = {1, 1, 2};
    vector<vector<int>> perms;
    vector<vector<int>> uniquePerms;
    permuteUnique(nums, perms, uniquePerms);
    printPermutations(uniquePerms);
    return 0;
}
